def _iter_techniques(obj: object) -> tuple[list[dict], _Index]:
    """Return (technique_list, index) from a STIX bundle dict."""
    if not isinstance(obj, dict):
        return [], _Index([])
    objects: list[dict] = obj.get("objects", [])
