// iterTechniques returns the list of live attack-pattern objects and a pre-built
// Index from a STIX bundle represented as map[string]interface{}.
func iterTechniques(obj interface{}) ([]map[string]interface{}, *Index) {
	bundle, ok := obj.(map[string]interface{})
	if !ok {
		return nil, NewIndex(nil)
	}
	raw, _ := bundle["objects"].([]interface{})
	objects := make([]map[string]interface{}, 0, len(raw))
	for _, item := range raw {
		if m, ok := item.(map[string]interface{}); ok {
			objects = append(objects, m)
		}
	}
	var techniques []map[string]interface{}
	for _, o := range objects {
		if o["type"] == "attack-pattern" && isLive(o) {
			techniques = append(techniques, o)
		}
	}
	return techniques, NewIndex(objects)
}

