// iterStudies normalises various ClinicalTrials.gov JSON layouts into a flat
// slice of study maps.
func iterStudies(obj interface{}) []map[string]interface{} {
	switch v := obj.(type) {
	case map[string]interface{}:
		if raw, ok := v["studies"].([]interface{}); ok {
			var out []map[string]interface{}
			for _, s := range raw {
				if m, ok := s.(map[string]interface{}); ok {
					out = append(out, m)
				}
			}
			return out
		}
		if _, ok := v["protocolSection"]; ok {
			return []map[string]interface{}{v}
		}
	case []interface{}:
		var out []map[string]interface{}
		for _, s := range v {
			if m, ok := s.(map[string]interface{}); ok {
				if _, hasPS := m["protocolSection"]; hasPS {
					out = append(out, m)
				}
			}
		}
		return out
	}
	return nil
}

// renderOneStudy renders a single ClinicalTrials.gov study record to markdown.
func renderOneStudy(study map[string]interface{}) string {
	ps := mapGet(study, "protocolSection")
	ident := mapGet(ps, "identificationModule")
	nctID := strGetDef(ident, "nctId", "UNKNOWN")
	title := strGetDef(ident, "briefTitle", strGetDef(ident, "officialTitle", ""))

	statusMod := mapGet(ps, "statusModule")
	status := strGetDef(statusMod, "overallStatus", "")
	designMod := mapGet(ps, "designModule")
	phaseRaw, _ := designMod["phases"].([]interface{})
	var phaseList []string
	for _, p := range phaseRaw {
		if s, ok := p.(string); ok {
			phaseList = append(phaseList, s)
		}
	}
	phases := strings.Join(phaseList, ", ")

	descMod := mapGet(ps, "descriptionModule")
	brief := strings.TrimSpace(strGetDef(descMod, "briefSummary", ""))
	detailed := strings.TrimSpace(strGetDef(descMod, "detailedDescription", ""))

	condsMod := mapGet(ps, "conditionsModule")
	condsRaw, _ := condsMod["conditions"].([]interface{})
	var conditions []string
	for _, c := range condsRaw {
		if s, ok := c.(string); ok {
			conditions = append(conditions, s)
		}
	}

	armsMod := mapGet(ps, "armsInterventionsModule")
	ivsRaw, _ := armsMod["interventions"].([]interface{})
	var interventions []string
	for _, item := range ivsRaw {
		iv, ok := item.(map[string]interface{})
		if !ok {
			continue
		}
		itype := strGetDef(iv, "type", "")
		iname := strGetDef(iv, "name", "")
		if iname != "" {
			if itype != "" {
				interventions = append(interventions, fmt.Sprintf("%s: %s", itype, iname))
			} else {
				interventions = append(interventions, iname)
			}
		}
	}

	eligMod := mapGet(ps, "eligibilityModule")
	eligibility := strings.TrimSpace(strGetDef(eligMod, "eligibilityCriteria", ""))
	minAge := strGetDef(eligMod, "minimumAge", "")
	maxAge := strGetDef(eligMod, "maximumAge", "")
	sex := strGetDef(eligMod, "sex", "")

	lines := []string{fmt.Sprintf("# %s %s", nctID, title), ""}

	var meta []string
	if status != "" {
		meta = append(meta, fmt.Sprintf("**Status:** %s", status))
	}
	if phases != "" {
		meta = append(meta, fmt.Sprintf("**Phase:** %s", phases))
	}
	if len(conditions) > 0 {
		cap := conditions
		if len(cap) > 5 {
			cap = cap[:5]
		}
		meta = append(meta, fmt.Sprintf("**Conditions:** %s", strings.Join(cap, ", ")))
	}
	lines = append(lines, meta...)

	if brief != "" {
		lines = append(lines, "", "## Summary", "", brief)
	}
	if detailed != "" {
		lines = append(lines, "", "## Detailed Description", "", detailed)
	}
	if len(interventions) > 0 {
		lines = append(lines, "", "## Interventions", "")
		cap := interventions
		if len(cap) > 10 {
			cap = cap[:10]
		}
		for _, iv := range cap {
			lines = append(lines, fmt.Sprintf("- %s", iv))
		}
	}
	if eligibility != "" {
		var ageParts []string
		if minAge != "" {
			ageParts = append(ageParts, minAge)
		}
		if maxAge != "" {
			ageParts = append(ageParts, maxAge)
		}
		ageStr := strings.Join(ageParts, " to ")
		eligHeader := "## Eligibility"
		if sex != "" || ageStr != "" {
			eligHeader = fmt.Sprintf("## Eligibility (%s, %s)", sex, ageStr)
		}
		eligText := eligibility
		if len(eligText) > 2000 {
			eligText = eligText[:2000]
		}
		lines = append(lines, "", eligHeader, "", eligText)
	}
	return strings.Join(lines, "\n")
}

