type ClinicalTrialRenderer struct{}

// CanRender returns true if obj contains valid ClinicalTrials.gov study data.
func (r *ClinicalTrialRenderer) CanRender(sourcePath *string, obj interface{}) bool {
	studies := iterStudies(obj)
	if len(studies) == 0 {
		return false
	}
	limit := 3
	if len(studies) < limit {
		limit = len(studies)
	}
	for _, s := range studies[:limit] {
		ps := mapGet(s, "protocolSection")
		ident := mapGet(ps, "identificationModule")
		if nctID, ok := ident["nctId"].(string); ok && nctID != "" {
			return true
		}
	}
	return false
}

