// CsvExtractor extracts CSV/TSV files into markdown tables.
type CsvExtractor struct{}

// cellEscape escapes pipe characters and strips newlines for markdown table cells.
func cellEscape(value string) string {
	value = strings.ReplaceAll(value, "|", "\\|")
	value = strings.ReplaceAll(value, "\n", " ")
	return strings.TrimSpace(value)
}

// Extract decodes CSV/TSV bytes and returns a markdown table string.
func (e *CsvExtractor) Extract(data []byte, sourcePath *string) (string, error) {
	text, err := decodeBytes(data)
	if err != nil {
		return "", fmt.Errorf("CsvExtractor.Extract: decode: %w", err)
	}

	rows, err := parseCSVRows(text)
	if err != nil {
		return "", fmt.Errorf("CsvExtractor.Extract: parse: %w", err)
	}
	if len(rows) == 0 {
		return "", nil
	}

	headers := rows[0]
	body := rows[1:]

	var headerCells []string
	for _, h := range headers {
		headerCells = append(headerCells, cellEscape(h))
	}
	headerRow := "| " + strings.Join(headerCells, " | ") + " |"

	var sepCells []string
	for range headers {
		sepCells = append(sepCells, "---")
	}
	sepRow := "| " + strings.Join(sepCells, " | ") + " |"

	var allRows []string
	allRows = append(allRows, headerRow, sepRow)
	for _, row := range body {
		var cells []string
		for _, c := range row {
			cells = append(cells, cellEscape(c))
		}
		allRows = append(allRows, "| "+strings.Join(cells, " | ")+" |")
	}
	return strings.Join(allRows, "\n"), nil
}

