func (e *CsvExtractor) Annotate(chunks []*DocumentChunk, data []byte, sourcePath *string) ([]*DocumentChunk, error) {
	text, err := decodeBytes(data)
	if err != nil {
		return nil, fmt.Errorf("CsvExtractor.Annotate: decode: %w", err)
	}
	rows, err := parseCSVRows(text)
	if err != nil {
		return nil, fmt.Errorf("CsvExtractor.Annotate: parse: %w", err)
	}
	if len(rows) < 2 {
		return chunks, nil
	}

	var rowMap []rowEntry
	for i, row := range rows[1:] {
		var cells []string
		for _, c := range row {
			cells = append(cells, cellEscape(c))
		}
		renderedRow := "| " + strings.Join(cells, " | ") + " |"
		rowMap = append(rowMap, rowEntry{index: i + 1, rendered: renderedRow})
	}

	for _, chunk := range chunks {
		content := chunk.Content
		var matched []int
		for _, entry := range rowMap {
			if strings.Contains(content, entry.rendered) {
				matched = append(matched, entry.index)
			}
		}
		if len(matched) > 0 {
			minR, maxR := matched[0], matched[0]
			for _, idx := range matched[1:] {
				if idx < minR {
					minR = idx
				}
				if idx > maxR {
					maxR = idx
				}
			}
			chunk.SourceDetail = map[string]interface{}{
				"row_start": minR,
				"row_end":   maxR,
			}
		}
	}
	return chunks, nil
}

