			scoreRaw, hasScore := data["baseScore"]
			if !hasScore || scoreRaw == nil {
				continue
			}
			var score float64
			switch v := scoreRaw.(type) {
			case float64:
				score = v
			case float32:
				score = float64(v)
			default:
				continue
