// cpeReadable converts a CPE criteria string and version-range match map into a
// human-readable vendor/product string with optional version ranges.
func cpeReadable(criteria string, match map[string]interface{}) string {
	parts := strings.Split(criteria, ":")
	var base string
	if len(parts) >= 6 {
		vendor := strings.ReplaceAll(parts[3], "_", " ")
		product := strings.ReplaceAll(parts[4], "_", " ")
		base = fmt.Sprintf("%s/%s", vendor, product)
	} else {
		base = criteria
	}

	var ranges []string
	if v := strGetDef(match, "versionStartIncluding", ""); v != "" {
		ranges = append(ranges, fmt.Sprintf(">= %s", v))
	}
	if v := strGetDef(match, "versionStartExcluding", ""); v != "" {
		ranges = append(ranges, fmt.Sprintf("> %s", v))
	}
	if v := strGetDef(match, "versionEndIncluding", ""); v != "" {
		ranges = append(ranges, fmt.Sprintf("<= %s", v))
	}
	if v := strGetDef(match, "versionEndExcluding", ""); v != "" {
		ranges = append(ranges, fmt.Sprintf("< %s", v))
	}

	if len(ranges) > 0 {
		return fmt.Sprintf("%s (%s)", base, strings.Join(ranges, ", "))
	}
	version := ""
	if len(parts) >= 6 && parts[5] != "*" {
		version = parts[5]
	}
	return strings.TrimSpace(fmt.Sprintf("%s %s", base, version))
}

