// extractDocxContent extracts text from a parsed DOCX document as markdown.
// doc is assumed to be a *docxlib.Document from a Go DOCX library.
func extractDocxContent(doc DocxDocument) string {
	var paragraphs []string

	for _, para := range doc.Paragraphs() {
		text := strings.TrimSpace(para.Text())
		if text == "" {
			continue
		}
		name := styleName(para)
		if strings.HasPrefix(name, "Heading") {
			levelStr := strings.TrimPrefix(name, "Heading ")
			levelNum, err := strconv.Atoi(levelStr)
			if err == nil {
				paragraphs = append(paragraphs, fmt.Sprintf("%s %s", strings.Repeat("#", levelNum), text))
			} else {
				paragraphs = append(paragraphs, text)
			}
		} else {
			paragraphs = append(paragraphs, text)
		}
	}

	for _, table := range doc.Tables() {
		var tableRows []string
		for _, row := range table.Rows() {
			var cells []string
			for _, cell := range row.Cells() {
				cells = append(cells, strings.TrimSpace(cell.Text()))
			}
			tableRows = append(tableRows, strings.Join(cells, " | "))
		}
		if len(tableRows) > 0 {
			paragraphs = append(paragraphs, strings.Join(tableRows, "\n"))
		}
	}

	return strings.Join(paragraphs, "\n\n")
}

