// paraRecord holds an original paragraph index, its text, and heading breadcrumbs.
type paraRecord struct {
	origIdx int
	text    string
	section []string
}

// Annotate finds which source paragraphs appear in each chunk and sets
// source_detail with paragraph indices and section breadcrumbs.
func (e *DocxExtractor) Annotate(chunks []*DocumentChunk, data []byte, sourcePath *string) ([]*DocumentChunk, error) {
	if !docxAvailable {
		sp := "unknown"
		if sourcePath != nil {
			sp = *sourcePath
		}
		return nil, fmt.Errorf("pip install chonk[docx] (loading %s)", sp)
	}

	doc, err := openDocx(data)
	if err != nil {
		return nil, fmt.Errorf("DocxExtractor.Annotate: open: %w", err)
	}

	var paraRecords []paraRecord
	var headingStack []string

	for origIdx, para := range doc.Paragraphs() {
		text := strings.TrimSpace(para.Text())
		if text == "" {
			continue
		}
		name := styleName(para)
		if strings.HasPrefix(name, "Heading") {
			levelStr := strings.TrimPrefix(name, "Heading ")
			if level, err := strconv.Atoi(levelStr); err == nil {
				if level-1 < len(headingStack) {
					headingStack = headingStack[:level-1]
				}
				headingStack = append(headingStack, text)
			}
		}
		sectionCopy := make([]string, len(headingStack))
		copy(sectionCopy, headingStack)
		paraRecords = append(paraRecords, paraRecord{origIdx: origIdx, text: text, section: sectionCopy})
	}

	for _, chunk := range chunks {
		content := chunk.Content
		startIdx := -1
		endIdx := -1
		var sectionAtStart []string
		for _, pr := range paraRecords {
			if len(pr.text) >= 10 && strings.Contains(content, pr.text) {
				if startIdx == -1 {
					startIdx = pr.origIdx
					sectionAtStart = pr.section
				}
				endIdx = pr.origIdx
			}
		}
		if startIdx != -1 {
			chunk.SourceDetail = map[string]interface{}{
				"paragraph_start": startIdx,
				"paragraph_end":   endIdx,
				"section":         sectionAtStart,
			}
		}
	}
	return chunks, nil
}
